const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const CORE = path.join(PROJECT, 'src-tauri/src/core');

const readFile = (p) => {
  try { return fs.readFileSync(p, 'utf8'); } catch { return '// FILE NOT FOUND'; }
};

const context = {
  geometry: readFile(path.join(CORE, 'geometry.rs')),
  types: readFile(path.join(CORE, 'types.rs')),
  mod_rs: readFile(path.join(CORE, 'mod.rs')),
  element: readFile(path.join(CORE, 'element.rs')),
  cargo_toml: readFile(path.join(PROJECT, 'src-tauri/Cargo.toml')),
  existing_import: readFile(path.join(CORE, 'import.rs')),
  existing_import_stl: readFile(path.join(CORE, 'import_stl.rs')),
  existing_import_nec: readFile(path.join(CORE, 'import_nec.rs')),
  existing_import_nastran: readFile(path.join(CORE, 'import_nastran.rs')),
};

return [{ json: { context } }];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const CORE = path.join(PROJECT, 'src-tauri/src/core');

const agents = ['Gen STL Parser', 'Gen NEC Parser', 'Gen NASTRAN Parser', 'Gen Import Module'];
const fileRegex = /<file path="([^"]+)">\n?([\s\S]*?)<\/file>/g;
const results = {};
let filesWritten = 0;

for (const agentName of agents) {
  try {
    const output = $(agentName).item.json.output || '';
    let match;
    const regex = new RegExp(fileRegex.source, fileRegex.flags);
    while ((match = regex.exec(output)) !== null) {
      const filePath = match[1];
      const content = match[2].trim();
      const fullPath = path.join(PROJECT, filePath);
      const dir = path.dirname(fullPath);
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
      fs.writeFileSync(fullPath, content);
      results[filePath] = `WRITTEN (${content.length} chars)`;
      filesWritten++;
    }
  } catch (e) {
    results[agentName] = `ERROR: ${e.message}`;
  }
}

// cargo check
let cargoResult = '';
try {
  cargoResult = execSync('cd src-tauri && cargo check 2>&1', { cwd: PROJECT, timeout: 180000 }).toString();
  cargoResult = cargoResult.includes('error') ? cargoResult : 'OK';
} catch (e) {
  cargoResult = e.stdout?.toString() || e.message;
}

// cargo test for import modules
let testResult = '';
try {
  testResult = execSync('cd src-tauri && cargo test -- import 2>&1', { cwd: PROJECT, timeout: 120000 }).toString();
} catch (e) {
  testResult = e.stdout?.toString() || e.message;
}

return [{ json: { filesWritten, results, cargoResult, testResult } }];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const prev = $('Write + Cargo Check').item.json;
const needsFix = prev.cargoResult !== 'OK' || prev.testResult.includes('FAILED');
let fixResult = 'No fix needed';

if (needsFix) {
  const output = $('Self-Fix Agent').item.json.output || '';
  const fileRegex = /<file path="([^"]+)">\n?([\s\S]*?)<\/file>/g;
  let match;
  while ((match = fileRegex.exec(output)) !== null) {
    const fullPath = path.join(PROJECT, match[1]);
    const dir = path.dirname(fullPath);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(fullPath, match[2].trim());
  }
  try {
    execSync('cd src-tauri && cargo check 2>&1', { cwd: PROJECT, timeout: 180000 });
    fixResult = 'Fix applied — cargo check OK';
  } catch (e) {
    fixResult = 'Fix applied but still errors: ' + (e.stdout?.toString().slice(0, 500) || e.message);
  }
}

// Git commit
let gitResult = '';
try {
  execSync('git add -A', { cwd: PROJECT });
  execSync('git commit -m "feat(import): add CAD import parsers (STL, NEC, NASTRAN)\n\nAdded STL binary/ASCII parser, NEC2 card format parser,\nNASTRAN BDF parser, unified import dispatcher, and STEP loader stub."', { cwd: PROJECT });
  execSync('git push origin main', { cwd: PROJECT });
  gitResult = 'Committed and pushed';
} catch (e) {
  gitResult = 'Git: ' + e.message;
}

return [{ json: { ...prev, fixResult, gitResult, phase: 'cad-import', status: 'complete' } }];
